<?php namespace App\Http\Controllers; use App\Enums\AssetStatus;use App\Http\Requests\AssetRequest;use App\Models\Asset; class AssetController extends Controller{public function index(){return view('assets.index',['assets'=>Asset::query()->when(request('search'),fn($q,$s)=>$q->where('name','like',"%$s%")->orWhere('code','like',"%$s%"))->latest()->paginate(10),'statuses'=>AssetStatus::cases()]);} public function create(){return view('assets.form',['asset'=>new Asset,'statuses'=>AssetStatus::cases()]);} public function store(AssetRequest $r){Asset::create($r->all());return redirect()->route('assets.index')->with('toast','Asset created');} public function show(Asset $asset){return view('assets.show',compact('asset'));} public function edit(Asset $asset){return view('assets.form',['asset'=>$asset,'statuses'=>AssetStatus::cases()]);} public function update(AssetRequest $r,Asset $asset){$asset->update($r->all());return redirect()->route('assets.show',$asset)->with('toast','Asset updated');} public function destroy(Asset $asset){$asset->delete();return back()->with('toast','Asset deleted');}}
